// Add this method to ExtendedBufferedReader to allow mocking super.read()

package org.apache.commons.csv;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.Reader;

class ExtendedBufferedReader extends BufferedReader {

    ExtendedBufferedReader(Reader r) {
        super(r);
    }

    @Override
    public int read(char[] buf, int offset, int length) throws IOException {
        if (length == 0) {
            return 0;
        }

        int len = superRead(buf, offset, length);

        if (len > 0) {

            for (int i = offset; i < offset + len; i++) {
                char ch = buf[i];
                if (ch == '\n') {
                    if ('\r' != (i > 0 ? buf[i - 1] : lastChar)) {
                        lineCounter++;
                    }
                } else if (ch == '\r') {
                    lineCounter++;
                }
            }

            lastChar = buf[offset + len - 1];

        } else if (len == -1) {
            lastChar = END_OF_STREAM;
        }

        return len;
    }

    // Wrapper method to allow mocking super.read() in tests
    int superRead(char[] buf, int offset, int length) throws IOException {
        return super.read(buf, offset, length);
    }

    static final int END_OF_STREAM = -1;
    static final int UNDEFINED = -2;

    private int lastChar = UNDEFINED;
    private int lineCounter = 0;

    // other methods omitted for brevity
}
